import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const b=JSON.parse('{"title":"法源寺","description":"","frontmatter":{},"headers":[],"relativePath":"religion/fayuan.md","filePath":"religion/fayuan.md","lastUpdated":1784712887000}'),n={name:"religion/fayuan.md"};function i(o,t,d,h,s,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="法源寺" tabindex="-1">法源寺 <a class="header-anchor" href="#法源寺" aria-label="Permalink to &quot;法源寺&quot;">​</a></h1><blockquote><p>&quot;北京最古老的名刹，中国佛学院所在地。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>法源寺位于北京市西城区，是北京最古老的名刹之一，也是中国佛学院所在地。法源寺始建于唐贞观十九年（645年），距今已有1300余年历史。法源寺以丁香闻名，每年春季丁香盛开，香气袭人。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">8:00-16:00</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">5元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">1-2小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春季丁香</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁4号线/7号线菜市口站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市西城区法源寺前街7号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="始建" tabindex="-1">始建 <a class="header-anchor" href="#始建" aria-label="Permalink to &quot;始建&quot;">​</a></h3><p>法源寺始建于唐贞观十九年（645年），原名悯忠寺，是唐太宗为纪念东征阵亡将士而建。</p><h3 id="发展" tabindex="-1">发展 <a class="header-anchor" href="#发展" aria-label="Permalink to &quot;发展&quot;">​</a></h3><ul><li><strong>唐代</strong>：悯忠寺香火鼎盛</li><li><strong>辽代</strong>：辽道宗在此受戒</li><li><strong>金代</strong>：金世宗曾到此进香</li><li><strong>元代</strong>：改名为&quot;法源寺&quot;</li><li><strong>清代</strong>：乾隆年间重修，规模扩大</li><li><strong>现代</strong>：1980年代修复，成为中国佛学院所在地</li></ul><h2 id="建筑布局" tabindex="-1">建筑布局 <a class="header-anchor" href="#建筑布局" aria-label="Permalink to &quot;建筑布局&quot;">​</a></h2><h3 id="山门" tabindex="-1">山门 <a class="header-anchor" href="#山门" aria-label="Permalink to &quot;山门&quot;">​</a></h3><p>山门是法源寺的入口，门前有石狮。</p><h3 id="天王殿" tabindex="-1">天王殿 <a class="header-anchor" href="#天王殿" aria-label="Permalink to &quot;天王殿&quot;">​</a></h3><p>天王殿供奉弥勒佛和四大天王。</p><h3 id="大雄宝殿" tabindex="-1">大雄宝殿 <a class="header-anchor" href="#大雄宝殿" aria-label="Permalink to &quot;大雄宝殿&quot;">​</a></h3><p>大雄宝殿是法源寺的主殿，供奉释迦牟尼佛。</p><h3 id="悯忠台" tabindex="-1">悯忠台 <a class="header-anchor" href="#悯忠台" aria-label="Permalink to &quot;悯忠台&quot;">​</a></h3><p>悯忠台是法源寺最古老的建筑，是唐代悯忠寺的遗存。</p><h3 id="观音殿" tabindex="-1">观音殿 <a class="header-anchor" href="#观音殿" aria-label="Permalink to &quot;观音殿&quot;">​</a></h3><p>观音殿供奉观音菩萨。</p><h3 id="毗卢殿" tabindex="-1">毗卢殿 <a class="header-anchor" href="#毗卢殿" aria-label="Permalink to &quot;毗卢殿&quot;">​</a></h3><p>毗卢殿供奉毗卢遮那佛。</p><h3 id="藏经楼" tabindex="-1">藏经楼 <a class="header-anchor" href="#藏经楼" aria-label="Permalink to &quot;藏经楼&quot;">​</a></h3><p>藏经楼收藏佛教经典。</p><h2 id="丁香" tabindex="-1">丁香 <a class="header-anchor" href="#丁香" aria-label="Permalink to &quot;丁香&quot;">​</a></h2><p>法源寺以丁香闻名，是北京著名的丁香观赏地。</p><h3 id="丁香种植" tabindex="-1">丁香种植 <a class="header-anchor" href="#丁香种植" aria-label="Permalink to &quot;丁香种植&quot;">​</a></h3><p>法源寺种植了大量丁香，有紫丁香、白丁香等多个品种。</p><h3 id="丁香诗会" tabindex="-1">丁香诗会 <a class="header-anchor" href="#丁香诗会" aria-label="Permalink to &quot;丁香诗会&quot;">​</a></h3><p>每年春季丁香盛开时，法源寺举办丁香诗会，文人墨客聚集，吟诗作画。</p><h3 id="最佳观赏时间" tabindex="-1">最佳观赏时间 <a class="header-anchor" href="#最佳观赏时间" aria-label="Permalink to &quot;最佳观赏时间&quot;">​</a></h3><p>每年4月中旬至5月上旬，丁香盛开，香气袭人。</p><h2 id="中国佛学院" tabindex="-1">中国佛学院 <a class="header-anchor" href="#中国佛学院" aria-label="Permalink to &quot;中国佛学院&quot;">​</a></h2><p>法源寺是中国佛学院所在地，是中国佛教界的最高学府。</p><h3 id="佛学院" tabindex="-1">佛学院 <a class="header-anchor" href="#佛学院" aria-label="Permalink to &quot;佛学院&quot;">​</a></h3><p>中国佛学院成立于1956年，是培养佛教人才的最高学府。</p><h3 id="课程设置" tabindex="-1">课程设置 <a class="header-anchor" href="#课程设置" aria-label="Permalink to &quot;课程设置&quot;">​</a></h3><p>佛学院开设佛教经典、戒律、历史等课程。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约1-2小时）</strong>：</p><p>山门 → 天王殿 → 大雄宝殿 → 悯忠台 → 观音殿 → 毗卢殿 → 藏经楼 → 丁香园 → 出寺</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">4号线/7号线菜市口站D口</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">48路、66路、102路等菜市口西站</td></tr><tr><td style="text-align:left;">步行</td><td style="text-align:left;">从牛街步行约15分钟</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>门票便宜</strong>：门票仅5元</li><li><strong>丁香必看</strong>：春季丁香盛开，必看</li><li><strong>保持安静</strong>：佛学院所在地，保持安静</li><li><strong>尊重礼仪</strong>：尊重佛教礼仪</li><li><strong>结合游览</strong>：可与牛街、陶然亭一起游览</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">牛街</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">回族聚居区</td></tr><tr><td style="text-align:left;">陶然亭公园</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">城市公园</td></tr><tr><td style="text-align:left;">大观园</td><td style="text-align:center;">步行20分钟</td><td style="text-align:left;">红楼梦主题园</td></tr><tr><td style="text-align:left;">天坛</td><td style="text-align:center;">地铁2站</td><td style="text-align:left;">明清祭天圣地</td></tr></tbody></table><h2 id="文化价值" tabindex="-1">文化价值 <a class="header-anchor" href="#文化价值" aria-label="Permalink to &quot;文化价值&quot;">​</a></h2><p>法源寺是北京最古老的名刹之一，距今已有1300余年历史。</p><p>法源寺是中国佛学院所在地，是佛教教育和研究的重要场所。</p><p>法源寺的丁香是北京著名的春景，每年吸引大量游客。</p><hr><p><strong>📍 地址</strong>：北京市西城区法源寺前街7号 <strong>📞 电话</strong>：010-63534171</p>',56)])])}const f=a(n,[["render",i]]);export{b as __pageData,f as default};
